mapper.insert:
/* SQL ID : insertLessonStudyRecordBasic 설 명 : 학습기록 기본값 저장 */ INSERT ALL
INTO TB_LMS_LESSON_STUDY_RECORD ( STD_ID , SBJCT_LCTR_CONTS_ID , SBJCT_ID , ATNDLC_STSCD , STUDY_CNT , STUDY_SESSION_TM , STUDY_TOTAL_TM , STUDY_AFTER_TM , ATNDLC_SDTTM , STUDY_SESSION_DTTM , RCNT_ATNDLC_PSTN , PRGR_RATIO , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) VALUES ( #{item.stdNo} , #{item.lessonCntsId} , #{item.crsCreCd} , null , 0 , 0 , 0 , 0 , FN_DTTM() , FN_DTTM() , 0 , null , #{item.userId} , FN_DTTM() , #{item.userId} , FN_DTTM() )
SELECT * FROM SYS.DUAL

	/*
		 SQL ID : insertLessonStudyState
		 설  명 : 학습상태 기본값 저장
 	*/
 	INSERT INTO TB_LMS_LESSON_STUDY_STATE (
		  LCTR_SCHDL_ID
		, STD_ID
		, SBJCT_ID
		, USER_ID
		, ATNDLC_STSCD
		, STUDY_STATUS_CD_BAK
		, ATTEND_REASON
		, RGTR_ID
		, FRST_INQ_DTTM
		, MDFR_ID
		, MOD_DTTM
 	)
	VALUES (
		  #{lessonScheduleId}
		, #{stdNo}
		, #{crsCreCd}
		, #{userId}
		, #{studyStatusCd}
		, null
		, null
		, #{userId}
		, FN_DTTM()
		, #{userId}
		, FN_DTTM()
	)

	/*
		 SQL ID : saveLessonStudyRecord
		 설  명 : 학습기록 저장(UPDATE)
 	*/
 	UPDATE TB_LMS_LESSON_STUDY_RECORD SET
 		  STUDY_CNT = #{studyCnt}
		, STUDY_SESSION_TM = #{studySessionTm}
		, STUDY_TOTAL_TM = #{studyTotalTm}
		, STUDY_AFTER_TM = #{studyAfterTm}
		, STUDY_SESSION_DTTM = FN_DTTM()
		, RCNT_ATNDLC_PSTN = #{studySessionLoc}
		, PRGR_RATIO = #{prgrRatio}
		, MDFR_ID = #{userId}
		, MOD_DTTM = FN_DTTM()
	WHERE 1=1
		AND STD_ID = #{stdNo}
		AND SBJCT_LCTR_CONTS_ID = #{lessonCntsId}
		AND SBJCT_ID = #{crsCreCd}

	/*
		 SQL ID : saveLessonStudyState
		 설  명 : 주차 학습상태 저장(UPDATE)
 	*/
 	UPDATE TB_LMS_LESSON_STUDY_STATE SET
 		  ATNDLC_STSCD = #{studyStatusCd}
 		, MDFR_ID = #{userId}
		, MOD_DTTM = FN_DTTM()
	WHERE 1=1
		AND LCTR_SCHDL_ID = #{lessonScheduleId}
		AND STD_ID = #{stdNo}

	/*
		 SQL ID : saveLessonStudyPage
		 설  명 : 페이지 학습기록 저장(UPDATE)
 	*/
 	UPDATE TB_LMS_LESSON_STUDY_PAGE SET 
 		  STUDY_CNT = #{studyCnt}
		, STUDY_SESSION_TM = #{studySessionTm}
		, STUDY_SESSION_DTTM = FN_DTTM()
		, RCNT_ATNDLC_PSTN = #{studySessionLoc}
		, PRGR_RATIO = #{prgrRatio}
		, MDFR_ID = #{userId}
		, MOD_DTTM = FN_DTTM()
	WHERE 1=1
		AND SBJCT_LCTR_CONTS_ID = #{lessonCntsId}
		AND STD_ID = #{stdNo}
		AND PAGE_SEQNO = #{pageCnt}
		AND SBJCT_ID = #{crsCreCd}

	/*
		 SQL ID : insertLessonStudyDetail
		 설  명 : 학습기록 상세 저장
 	*/
 	INSERT INTO TB_LMS_LESSON_STUDY_DETAIL (
		  ATNDLC_RCD_DTL_ID
		, STD_ID
		, SBJCT_LCTR_CONTS_ID
		, SBJCT_ID
		, STUDY_CNT
		, ATNDLC_MNTS
		, ATNDLC_BRWSR
		, ATNDLC_CNTN_DVC_CD
		, STD_ID
		, RGTR_IP
		, RGTR_ID
		, FRST_INQ_DTTM
 	)
	VALUES (
		  #{studyDetailId}
		, #{stdNo}
		, #{lessonCntsId}
		, #{crsCreCd}
		, #{studyCnt}
		, #{studyTm}
		, #{studyBrowserCd}
		, #{studyDeviceCd}
		, #{studyClientEnv}
		, #{regIp}
		, #{userId}
		, FN_DTTM()
	)

mapper.delete:
		/*
             SQL ID : deleteLessonStudyRecord
             설  명 : 수강생 학습기록 삭제
         */
		DELETE FROM TB_LMS_LESSON_STUDY_RECORD
		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

			AND STD_ID = #{stdNo}

		/*
             SQL ID : deleteLessonStudyDetail
             설  명 : 수강생 학습기록 상세 삭제
         */
		DELETE FROM TB_LMS_LESSON_STUDY_DETAIL
		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

			AND STD_ID = #{stdNo}


			AND ATNDLC_RCD_DTL_ID = #{studyDetailId}

		/*
             SQL ID : deleteLessonStudyPage
             설  명 : 수강생 페이지 학습기록 삭제
         */
		DELETE FROM TB_LMS_LESSON_STUDY_PAGE
		WHERE SBJCT_LCTR_CONTS_ID = #{lessonCntsId}

			AND STD_ID = #{stdNo}


			AND PAGE_SEQNO = #{pageCnt}

mapper.update:
		/*
             SQL ID : insertForcedAttend
             설  명 : 강제 출석 처리 저장
         */
		INSERT INTO TB_LMS_LESSON_STUDY_STATE (
			  LCTR_SCHDL_ID
			, STD_ID
			, SBJCT_ID
			, USER_ID
			, ATNDLC_STSCD
			, STUDY_STATUS_CD_BAK
			, ATTEND_REASON
			, RGTR_ID
			, FRST_INQ_DTTM
		) VALUES (
			  #{lessonScheduleId}
			, #{stdNo}
			, #{crsCreCd}
			, (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = #{stdNo})
			, #{studyStatusCd}
			, 'NOSTUDY'
			, #{attendReason}
			, #{rgtrId}
			, FN_DTTM()
		)

		/*
             SQL ID : updateForcedAttend
             설  명 : 강제 출석 처리 수정
         */
		UPDATE TB_LMS_LESSON_STUDY_STATE
		SET
			  ATNDLC_STSCD = #{studyStatusCd}
			, STUDY_STATUS_CD_BAK = #{studyStatusCdBak}
			, ATTEND_REASON = #{attendReason}
			, MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
		WHERE LCTR_SCHDL_ID = #{lessonScheduleId}
		AND STD_ID = #{stdNo}
		AND ATNDLC_STSCD != 'COMPLETE'
		AND STUDY_STATUS_CD_BAK IS NULL

		/*
             SQL ID : updateAttendReason
            	 설  명 : 출석 메모 수정
         */
		UPDATE TB_LMS_LESSON_STUDY_STATE
		SET
			  ATTEND_REASON = #{attendReason}
			, MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
		WHERE LCTR_SCHDL_ID = #{lessonScheduleId}
		AND STD_ID = #{stdNo}

		/*
             SQL ID : cancelForcedAttend
             설  명 : 강제 출석 처리 취소
         */
		UPDATE TB_LMS_LESSON_STUDY_STATE
		SET
			  ATNDLC_STSCD = #{studyStatusCd}
			, STUDY_STATUS_CD_BAK = NULL
			, ATTEND_REASON = NULL
			, MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
		WHERE LCTR_SCHDL_ID = #{lessonScheduleId}
		AND STD_ID = #{stdNo}
		AND ATNDLC_STSCD IN ('COMPLETE', 'LATE')
		AND STUDY_STATUS_CD_BAK IS NOT NULL

		/*
             SQL ID : updateForcedAttendLegal
             설  명 : 법정교육 강제 이수,미이수 처리
         */
		INSERT INTO TB_LMS_LESSON_STUDY_STATE (
			  LCTR_SCHDL_ID
			, STD_ID
			, SBJCT_ID
			, USER_ID
			, ATNDLC_STSCD
			, ATTEND_REASON
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES

		(
			  #{item.lessonScheduleId}
			, #{item.stdNo}
			, #{item.crsCreCd}
			, #{item.userId}
			, #{item.studyStatusCd}
			, #{item.attendReason}
			, #{item.userId}
			, FN_DTTM()
			, #{item.userId}
			, FN_DTTM()
		)

		ON DUPLICATE KEY UPDATE
		      ATNDLC_STSCD 	= VALUES(ATNDLC_STSCD)
		    , ATTEND_REASON 	= VALUES(ATTEND_REASON)
		    , MDFR_ID 			= VALUES(MDFR_ID)
		    , MOD_DTTM 			= FN_DTTM()

mapper.select:
		/*
             SQL ID : selectLessonStudyStateTm
             설  명 : 수강생 강의 주차 학습상태 조회(시간포함)
         */

		AND B.LCTR_SCHDL_ID = #{lessonScheduleId}

/* SQL ID : LessonStudyDAO.listStdLessonRecord 설 명 : 수강생별 학습기록 주차 목록 조회 */ SELECT E.FRST_INQ_DTTM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = E.SBJCT_ID) AS SBJCTNM , (SELECT DVCLAS_NO FROM TB_LMS_SBJCT WHERE SBJCT_ID = E.SBJCT_ID) AS DVCLAS_NO , A.LCTR_SCHDL_SEQ , B.LCTR_CLASTM_SEQ , C.LCTR_CONTSNM , NVL(E.STUDY_CNT,1) AS STUDY_CNT , E.ATNDLC_MNTS , E.ATNDLC_CNTN_DVC_CD , E.ATNDLC_BRWSR , E.STD_ID , E.RGTR_IP FROM TB_LMS_SBJCT_LCTR_SCHDL A JOIN TB_LMS_SBJCT_LCTR_CLASTM B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID JOIN TB_LMS_SBJCT_LCTR_CONTS C ON B.SBJCT_LCTR_CLASTM_ID = C.SBJCT_LCTR_CLASTM_ID AND C.DELYN = 'N' JOIN TB_LMS_LESSON_STUDY_RECORD D ON C.SBJCT_LCTR_CONTS_ID = D.SBJCT_LCTR_CONTS_ID AND D.STD_ID = #{stdNo} JOIN TB_LMS_LESSON_STUDY_DETAIL E ON D.SBJCT_LCTR_CONTS_ID = E.SBJCT_LCTR_CONTS_ID AND D.STD_ID = E.STD_ID WHERE A.SBJCT_ID = #{crsCreCd}
AND A.LCTR_SCHDL_ID = #{lessonScheduleId}
ORDER BY A.LCTR_SCHDL_SEQ, B.LCTR_CLASTM_SEQ, E.FRST_INQ_DTTM DESC

/* SQL ID : LessonStudyDAO.listStdRecordByCrs 설 명 : 강의실별 수강생 학습기록 목록 조회 */ SELECT A.SBJCT_ID , IFNULL(SUM(A.LCTR_TOC_LRN_SCNDS * 60), 0) AS LCTR_TOC_LRN_SCNDS , IFNULL(SUM(B.STUDY_TOTAL_TM), 0) AS STUDY_TOTAL_TM , IFNULL(SUM(B.STUDY_AFTER_TM), 0) AS STUDY_AFTER_TM , IFNULL(SUM(B.STUDY_TOTAL_TM), 0) + IFNULL(SUM(B.STUDY_AFTER_TM), 0) AS STUDY_SUM_TM FROM ( SELECT A.SBJCT_ID , A.LCTR_TOC_LRN_SCNDS , C.SBJCT_LCTR_CONTS_ID , D.STD_ID FROM TB_LMS_SBJCT_LCTR_SCHDL A JOIN TB_LMS_SBJCT_LCTR_CLASTM B ON A.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID JOIN TB_LMS_SBJCT_LCTR_CONTS C ON B.SBJCT_LCTR_CLASTM_ID = C.SBJCT_LCTR_CLASTM_ID AND C.DELYN = 'N' AND (C.LCTR_CONTS_GBNCD = 'VIDEO' OR C.LCTR_CONTS_GBNCD = 'VIDEO_LINK') AND C.PRG_RFLTYN = 'Y' LEFT JOIN TB_LMS_ATNDLC_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID AND D.ATNDLC_STSCD = 'S' AND USER_ID = #{userId} WHERE A.DELYN = 'N' AND A.SBJCT_ID IN
#{item}
) A LEFT JOIN TB_LMS_LESSON_STUDY_RECORD B ON A.SBJCT_LCTR_CONTS_ID = B.SBJCT_LCTR_CONTS_ID AND A.STD_ID = B.STD_ID GROUP BY A.SBJCT_ID

